tpl.source:
{
  "scope": "project",
  "nodes": {
    "parentWorkflow": "parent-workflow-styleskill",
    "loggerWorkflow": "logger-workflow-styleskill",
    "codebaseMcpStyle": "codebase-mcp-styleskill",
    "docStyle": "doc-styleskill",
    "fileIo": "file-io-styleskill",
    "netStyle": "net-styleskill",
    "scopeStyle": "scope-styleskill",
    "templateService": "template-service-styleskill",
    "variableStyle": "variable-styleskill",
    "zustandStoreStyle": "zustand-store-styleskill",
    "HOOK_USER_COMMAND": "HOOK_USER_COMMAND",
    "HOOK_ASSISTANT_COMMAND": "HOOK_ASSISTANT_COMMAND"
  },
  "agentsMd": {
    "sections": [
      {
        "title": "总原则",
        "text": "按照用户级 AGENTS.md 处理。"
      }
    ]
  },
  "configToml": {
    "shellEnvironmentPolicy": {
      "inherit": "all",
      "exclude": [
        "ELECTRON_RUN_AS_NODE"
      ]
    },
    "features": {
      "hooks": true
    },
    "hooks": {
      "UserPromptSubmit": [
        {
          "type": "command",
          "command": "HOOK_USER_COMMAND",
          "timeout": 10
        }
      ],
      "Stop": [
        {
          "type": "command",
          "command": "HOOK_ASSISTANT_COMMAND",
          "timeout": 10
        }
      ]
    }
  },
  "skills": {}
}
